// Hardcoded opening book — maps position keys (first 4 FEN fields) to
// sound book moves in SAN. When a position is in book, the AI plays
// one of the listed moves instead of searching, producing varied and
// principled opening play for free.
//
// Covers mainline theory ~6-10 plies deep for:
//   White: Italian, Ruy Lopez, Queen's Gambit, London, English
//   Black: Sicilian, French, Caro-Kann, KID, Slav
//
// Generated by scripts/gen-opening-book.js and validated against chess.js.

/** Extract the position-only portion of a FEN (piece placement + side to
 * move + castling + en passant). Drops halfmove and fullmove counters
 * since they don't change the position itself. */
export function positionKey(fen: string): string {
  return fen.split(' ').slice(0, 4).join(' ');
}

